## Design
```php
final readonly class ToolResult {
    public function __construct(
        private string $content,
        private ?string $callId = null,     // links to ToolCall::id() — all providers except Gemini
        private ?string $toolName = null,   // function name — needed by Gemini for linking, useful for all
        private bool $isError = false,      // Anthropic supports natively, useful generically
    ) {}

    public static function success(string $content, ?string $callId = null, ?string $toolName = null): self;
    public static function error(string $content, ?string $callId = null, ?string $toolName = null): self;
    public static function fromArray(array $data): self;

    public function content(): string;
    public function callId(): ?string;
    public function toolName(): ?string;
    public function isError(): bool;

    public function toArray(): array;
}
```

